/**
 * MedX radius theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Border radius tokens for inputs and panels.
 */
const RADIUS_TOKENS = Object.freeze({
  primary: { value: "theme-radius-primary", scope: "theme" },
  secondary: { value: "theme-radius-secondary", scope: "theme" },
  muted: { value: "theme-radius-muted", scope: "theme" },
  accent: { value: "theme-radius-accent", scope: "theme" },
  surface: { value: "theme-radius-surface", scope: "theme" },
});

const RADIUS_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const RADIUS_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const radiusRegistry = new Map();
const RADIUS_listeners = new Set();
let RADIUS_seq = 0;

function createRadiusId(prefix = "medx-theme-radius") {
  RADIUS_seq += 1;
  return `${prefix}-${RADIUS_seq}`;
}

function registerRadius(config = {}) {
  const entryId = config.id ?? createRadiusId();
  const preset = RADIUS_PRESETS[config.preset ?? "default"] ?? RADIUS_PRESETS.default;
  const token = RADIUS_TOKENS[config.token ?? preset.token] ?? RADIUS_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: RADIUS_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  radiusRegistry.set(entryId, entry);
  notifyRadiusListeners("register", entry);
  return entry;
}

function updateRadius(id, patch = {}) {
  const entry = radiusRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyRadiusListeners("update", entry);
  return entry;
}

function resolveRadius(id) {
  const entry = radiusRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listRadiusEntries(filter = {}) {
  let items = Array.from(radiusRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onRadiusEvent(listener) {
  RADIUS_listeners.add(listener);
  return () => RADIUS_listeners.delete(listener);
}

function notifyRadiusListeners(type, entry) {
  for (const listener of RADIUS_listeners) {
    try {
      listener({ type, entry, registrySize: radiusRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:radius] listener error", err.message);
    }
  }
}

function getRadiusMetrics() {
  const items = listRadiusEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(RADIUS_TOKENS).length,
    presets: Object.keys(RADIUS_PRESETS).length,
  };
}

async function runMedxRadius() {
  console.log("[medx:ui:theme:radius] runtime initialized");
  console.log(`[medx:ui:theme:radius] tokens=${Object.keys(RADIUS_TOKENS).length} presets=${Object.keys(RADIUS_PRESETS).length}`);

  const events = [];
  onRadiusEvent((e) => events.push(e.type));

  const domains = Object.keys(RADIUS_SUPPLY_CHAIN);
  const presets = Object.keys(RADIUS_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerRadius({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/radius" },
    });
  }

  const first = listRadiusEntries()[0];
  if (first) updateRadius(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getRadiusMetrics();
  const resolved = first ? resolveRadius(first.id) : null;

  console.log(`[medx:ui:theme:radius] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:radius] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:radius] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:radius] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:radius] bootstrap complete");
}

module.exports = runMedxRadius;
